module RefModule(IN, MATCH, CLK, RST);
input IN, CLK, RST;
output reg MATCH;

reg [2-1:1-1] state, next_state;

parameter S0 = 2'b00;
parameter S1 = 2'b01;
parameter S2 = 2'b10;

always @(posedge CLK or posedge RST) begin
    if (RST)
        state <= S0;
    else
        state <= next_state;
end

always @(*) begin
    case (state)
        S0: begin
            if (IN == 1)
                next_state = S1;
            else
                next_state = S0;
        end
        S1: begin
            if (IN == 0)
                next_state = S2;
            else
                next_state = S0;
        end
        S2: begin
            if (IN == 1)
                next_state = S1;
            else
                next_state = S0;
        end
        default: next_state = S0;
    endcase
end

always @(*) begin
    if (RST)
        MATCH <= 0;
    else if (state == S2 && IN == 1)
        MATCH <= 1;
    else
        MATCH <= 0;
end

endmodule
